#include <bits/stdc++.h>
using namespace std;

ifstream fin("poduri.in");
ofstream fout("poduri.out");

int rowNo, colNo;
int xPoz, yPoz;
char mat[2051][2051];
int distances[2051][2051];

int rowNum[] = {-1, 0, 0, 1};
int colNum[] = {0, -1, 1, 0};

int rowNumV[] = {-1, 1};
int colNumV[] = {0, 0};

int rowNumO[] = {0, 0};
int colNumO[] = {1, -1};

void Lee(int xPoz, int yPoz) {
    queue<pair<int, int>> Q;
    Q.push(make_pair(xPoz, yPoz));
    distances[xPoz][yPoz] = 1;

    while (!Q.empty()) {
        int i = Q.front().first;
        int j = Q.front().second;

        if (mat[i][j] == 'V') {
                for (int k = 0 ; k < 2 ; k ++) {
                    int iAux = i + rowNumV[k];
                    int jAux = j + colNumV[k];
                    if (iAux >= 1
                    && iAux <= rowNo
                    && jAux >= 1
                    && jAux <= colNo
                    && distances[iAux][jAux] == 0
                    && mat[iAux][jAux] != '.') {
                        distances[iAux][jAux] = distances[i][j] + 1;
                        Q.push(make_pair(iAux , jAux));
                    }
                }
            }

        if (mat[i][j] == 'O') {
                for (int k = 0 ; k < 2 ; k ++) {
                    int iAux = i + rowNumO[k];
                    int jAux = j + colNumO[k];
                    if (iAux >= 1
                        && iAux <= rowNo
                        && jAux >= 1
                        && jAux <= colNo
                        && distances[iAux][jAux] == 0
                        && mat[iAux][jAux] != '.') {
                        distances[iAux][jAux] = distances[i][j] + 1;
                        Q.push(make_pair(iAux, jAux));
                    }
                }
            }

        if (mat[i][j] == 'D') {
                for (int k = 0 ; k < 4 ; k ++) {
                    int iAux = i + rowNum[k];
                    int jAux = j + colNum[k];
                    if (iAux >= 1
                        && iAux <= rowNo
                        && jAux >= 1
                        && jAux <= colNo
                        && distances[iAux][jAux] == 0
                        && mat[iAux][jAux] != '.') {
                        distances[iAux][jAux] = distances[i][j] + 1;
                        Q.push(make_pair(iAux , jAux));
                    }
                }
            }
        Q.pop();
    }
}

int main() {
    int k = -1;

	fin >> rowNo >> colNo;
    fin >> xPoz >> yPoz;

    bool potential[rowNo + 1][colNo + 1];

    for (int i = 1; i <= rowNo; i++) {
        for (int j = 1; j <= colNo; j++) {
