        }
    }

    int mini = INT_MAX;

    Lee(xPoz, yPoz);
    for (int i = 1; i <= rowNo; i++) {
        if (mat[i][1] == 'O' || mat[i][1] == 'D') {
            if (distances[i][1] < mini && distances[i][1] != 0)
                mini = distances[i][1];
        }

        if (mat[i][colNo] == 'O' || mat[i][colNo] == 'D') {
            if (distances[i][colNo] < mini && distances[i][colNo] != 0) {
                    mini = distances[i][colNo];
                }
        }
    }

    for (int j = 1; j <= colNo; j++) {
        if (mat[1][j] == 'V' || mat[1][j] == 'D') {
            if (distances[1][j] < mini && distances[1][j] != 0)
                mini = distances[1][j];
        }

        if (mat[rowNo][j] == 'V' || mat[rowNo][j] == 'D') {
            if (distances[rowNo][j] < mini && distances[rowNo][j] != 0)
                mini = distances[rowNo][j];
        }
    }
	fout << mini;

	return 0;
